from fastapi import FastAPI
from pydantic import BaseModel
from models import User, Workout, Progress

app = FastAPI()

class UserIn(BaseModel):
    user_id: int
    name: str
    email: str

class WorkoutIn(BaseModel):
    workout_id: int
    user_id: int
    exercise: str
    sets: int
    reps: int

class ProgressIn(BaseModel):
    progress_id: int
    user_id: int
    workout_id: int
    date: str
    weight: float

@app.post('/users')
async def create_user(user: UserIn):
    return user

@app.get('/users/{user_id}')
async def read_user(user_id: int):
    return {'user_id': user_id}

@app.post('/workouts')
async def create_workout(workout: WorkoutIn):
    return workout

@app.get('/workouts/{workout_id}')
async def read_workout(workout_id: int):
    return {'workout_id': workout_id}

@app.post('/progress')
async def create_progress(progress: ProgressIn):
    return progress

@app.get('/progress/{progress_id}')
async def read_progress(progress_id: int):
    return {'progress_id': progress_id}

from models import User, Workout, Progress

class UserService:
    def __init__(self):
        self.users = []

    def create_user(self, user: User):
        self.users.append(user)
        return user

    def get_user(self, user_id: int):
        for user in self.users:
            if user.user_id == user_id:
                return user
        return None

class WorkoutService:
    def __init__(self):
        self.workouts = []

    def create_workout(self, workout: Workout):
        self.workouts.append(workout)
        return workout

    def get_workout(self, workout_id: int):
        for workout in self.workouts:
            if workout.workout_id == workout_id:
                return workout
        return None

class ProgressService:
    def __init__(self):
        self.progress = []

    def create_progress(self, progress: Progress):
        self.progress.append(progress)
        return progress

    def get_progress(self, progress_id: int):
        for p in self.progress:
            if p.progress_id == progress_id:
                return p
        return None

import pytest
from fastapi.testclient import TestClient
from api import app, UserIn, WorkoutIn, ProgressIn

client = TestClient(app)

class TestAPI:
    def test_create_user(self):
        user_in = {'user_id': '1', 'name': 'John Doe', 'email': 'john@example.com'}
        response = client.post('/users', json=user_in)
        assert response.status_code == 200
        assert response.json() == user_in

    def test_read_user(self):
        user_in = {'user_id': '1', 'name': 'John Doe', 'email': 'john@example.com'}
        client.post('/users', json=user_in)
        response = client.get('/users/1')
        assert response.status_code == 200
        assert response.json() == {'user_id': '1'}

    def test_create_workout(self):
