        assert response.json() == workout_in

    def test_read_workout(self):
        workout_in = {'user_id': '1', 'workout_name': 'Workout 1', 'description': 'This is a workout'}
        client.post('/workouts', json=workout_in)
        response = client.get('/workouts/1')
        assert response.status_code == 200
        assert response.json() == {'user_id': '1'}

